sql.if:
AND EXISTS (
    SELECT 1
    FROM pq_answer_feature_score fs
    WHERE fs.answer_id = a.id
      AND fs.feature_id = #{criteria.featureId}
)

if.foreach:
AND EXISTS (
    SELECT 1
    FROM pq_answer_feature_score fsf
    WHERE fsf.answer_id = a.id
      AND fsf.feature_id = #{scoreFilter.featureId}

      AND fsf.score >= #{scoreFilter.min}


      AND fsf.score <= #{scoreFilter.max}

)

LEFT JOIN pq_answer_feature_score ${sort.alias}
    ON ${sort.alias}.answer_id = a.id
   AND ${sort.alias}.feature_id = #{sort.featureId}

mapper.select:
SELECT a.id AS answer_id, o.id AS opinion_id, a.questionnaire_id, p.product_model, p.product_code, a.answer_time, a.rom_version, a.app_version, a.feedback_text, a.score_reason, a.recommend_score, a.user_category, o.sentiment_code AS sentiment, f.feature_name, o.feedback_content_1, o.feedback_content_2 FROM pq_opinion o INNER JOIN pq_answer a ON a.id = o.answer_id INNER JOIN pq_product p ON p.id = a.product_id LEFT JOIN pq_feature f ON f.id = o.feature_id
WHERE 1 = 1
LIMIT #{limit} OFFSET #{offset}

SELECT a.id AS answer_id, a.questionnaire_id, p.product_model, p.product_code, a.answer_time, a.rom_version, a.app_version, a.recommend_score, a.user_category FROM pq_answer a INNER JOIN pq_product p ON p.id = a.product_id
WHERE 1 = 1
LIMIT #{limit} OFFSET #{offset}

SELECT answer_id, feature_id, score FROM pq_answer_feature_score WHERE answer_id IN
#{answerId}
ORDER BY answer_id ASC, feature_id ASC
